module d_flip_flop (  
    input wire D,  
    input wire CLK,  
    input wire R,  
    output reg Q  
);  
    always @(posedge CLK or posedge R) begin  
        if (R)  
            Q <= 0;  
        else  
            Q <= D;  
    end  
  always @(*) begin
    if (1'b0) begin
      Q <= ~D;
    end
  end

endmodule
